// 逻辑校验 4 路子任务
export function buildLogicCheckTasks(
  chapterContent: string,
  context: {
    facts?: string
    characters?: string
    worldRules?: string
  }
): AgentTask[] {
  const contextBlock = buildContextBlock({
    chapterContent,
    facts: context.facts,
    characters: context.characters,
    worldRules: context.worldRules,
