/**
 * 多 Agent 并行任务服务
 * 用于复杂任务的并行多路 AI 分析（如逻辑校验、矛盾检测）
 */

import aiModelService, { TaskType as AIModelTaskType } from './aiModels'
import { TASKS, buildContextBlock } from '../prompts'
import type { TaskType } from '../prompts/tasks'

export interface AgentTask {
  id: string
  name: string
  /** 调用的 taskType，对应 aiModels 的任务类型映射 */
  taskType: AIModelTaskType
  prompt: string
  systemPrompt?: string
}

export interface AgentResult {
  id: string
  name: string
  success: boolean
  content?: string
  error?: string
  duration: number
}

// 逻辑校验 4 路子任务
export function buildLogicCheckTasks(
  chapterContent: string,
  context: {
    facts?: string
    characters?: string
    worldRules?: string
  }
): AgentTask[] {
  const contextBlock = buildContextBlock({
    chapterContent,
    facts: context.facts,
    characters: context.characters,
    worldRules: context.worldRules,
  })

  const buildTask = (taskKey: TaskType): AgentTask => {
    const task = TASKS[taskKey]
    return {
      id: taskKey.replace('Check', '-check'),
      name: task.name,
      taskType: task.taskType,
      prompt: task.role_persona + '\n\n' + contextBlock + '\n' + task.task,
    }
  }

  return [
    buildTask('powerCheck' as TaskType),
    buildTask('timelineCheck' as TaskType),
    buildTask('characterCheck' as TaskType),
    buildTask('causalCheck' as TaskType),
  ]
}

// 并行执行多个 agent
export async function runAgents(
  tasks: AgentTask[],
  onResult?: (result: AgentResult) => void
): Promise<AgentResult[]> {
  const results = await Promise.all(
    tasks.map(async (task) => {
      const taskStart = Date.now()
      try {
        const result = await aiModelService.call(
          task.taskType,
          task.prompt,
          task.systemPrompt ? { systemPrompt: task.systemPrompt } : {}
        )
        const agentResult: AgentResult = {
          id: task.id,
          name: task.name,
          success: result.success,
          content: result.content,
          error: result.error,
          duration: Date.now() - taskStart,
        }
        onResult?.(agentResult)
        return agentResult
      } catch (err: any) {
        const agentResult: AgentResult = {
          id: task.id,
          name: task.name,
          success: false,
          error: err?.message || '未知错误',
          duration: Date.now() - taskStart,
        }
        onResult?.(agentResult)
        return agentResult
      }
    })
  )
  return results
}

// 汇总多个 agent 结果为可读报告
export function summarizeResults(results: AgentResult[]): string {
  const lines: string[] = ['## 逻辑校验报告\n']
  const successCount = results.filter(r => r.success).length
  const totalDuration = results.reduce((sum, r) => sum + r.duration, 0)

  lines.push(`**检测范围：** ${results.length} 项  |  **耗时：** ${(totalDuration / 1000).toFixed(1)}s\n`)

  for (const r of results) {
    const icon = r.success ? '✅' : '❌'
    lines.push(`### ${icon} ${r.name}`)
    if (r.success && r.content) {
      lines.push(r.content.trim())
    } else if (!r.success) {
      lines.push(`**错误：** ${r.error}`)
    }
    lines.push('')
  }

  lines.push(`---\n*由 ${successCount}/${results.length} 个子 agent 协作完成*`)
  return lines.join('\n')
}
